import{_ as e,o as r,c as i,a0 as t}from"./chunks/framework.jwovEGr5.js";const b=JSON.parse('{"title":"超星学习通修改教程","description":"","frontmatter":{"title":"超星学习通修改教程","editLink":false},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),d={name:"index.md"};function l(s,a,o,n,p,h){return r(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="超星学习通修改教程" tabindex="-1">超星学习通修改教程 <a class="header-anchor" href="#超星学习通修改教程" aria-label="Permalink to &quot;超星学习通修改教程&quot;">​</a></h1><blockquote><p>使用 MT 管理器修改超星学习通 6.7.2 版本的详细教程。涵盖脱壳修复、功能修改、JS 注入等完整流程。</p></blockquote><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fill, minmax(280px, 1fr));gap:16px;margin:24px 0;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="🔧-脱壳修复" tabindex="-1">🔧 脱壳修复 <a class="header-anchor" href="#🔧-脱壳修复" aria-label="Permalink to &quot;🔧 脱壳修复&quot;">​</a></h3><p>逆向的第一步，去除加固保护。 <br><a href="/guide/unpack-repair.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="⏩-章节视频快进" tabindex="-1">⏩ 章节视频快进 <a class="header-anchor" href="#⏩-章节视频快进" aria-label="Permalink to &quot;⏩ 章节视频快进&quot;">​</a></h3><p>解除视频播放限制，支持倍速播放。 <br><a href="/guide/video-speedup.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="👥-多端登录" tabindex="-1">👥 多端登录 <a class="header-anchor" href="#👥-多端登录" aria-label="Permalink to &quot;👥 多端登录&quot;">​</a></h3><p>同时登录多设备不被挤下线。 <br><a href="/guide/ignore-kickoff.html">不理会下线 →</a> · <a href="/guide/prevent-kick-others.html">阻止挤别人下线 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="🚫-去除开屏广告" tabindex="-1">🚫 去除开屏广告 <a class="header-anchor" href="#🚫-去除开屏广告" aria-label="Permalink to &quot;🚫 去除开屏广告&quot;">​</a></h3><p>干掉启动页的 5 秒广告。 <br><a href="/guide/remove-splash-ad.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="🔄-去除更新" tabindex="-1">🔄 去除更新 <a class="header-anchor" href="#🔄-去除更新" aria-label="Permalink to &quot;🔄 去除更新&quot;">​</a></h3><p>阻止版本更新弹窗提示。 <br><a href="/guide/remove-update.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="📚-默认我学的课" tabindex="-1">📚 默认我学的课 <a class="header-anchor" href="#📚-默认我学的课" aria-label="Permalink to &quot;📚 默认我学的课&quot;">​</a></h3><p>进入课程列表默认显示&quot;我学的课&quot;。 <br><a href="/guide/default-student-courses.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="📝-自定义-js-注入" tabindex="-1">📝 自定义 JS 注入 <a class="header-anchor" href="#📝-自定义-js-注入" aria-label="Permalink to &quot;📝 自定义 JS 注入&quot;">​</a></h3><p>向 WebView 注入自定义 JavaScript 脚本。 <br><a href="/guide/inject-custom-js.html">添加 JS →</a> · <a href="/guide/enable-web-debug.html">开启调试 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="🎯-考试脱控" tabindex="-1">🎯 考试脱控 <a class="header-anchor" href="#🎯-考试脱控" aria-label="Permalink to &quot;🎯 考试脱控&quot;">​</a></h3><p>解除考试页面的切屏检测限制。 <br><a href="/guide/exam-control.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="📱-一机多签" tabindex="-1">📱 一机多签 <a class="header-anchor" href="#📱-一机多签" aria-label="Permalink to &quot;📱 一机多签&quot;">​</a></h3><p>同一设备多次签到解决方案。 <br><a href="/guide/multi-device-sign.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="💻-app-js-教程" tabindex="-1">💻 App JS 教程 <a class="header-anchor" href="#💻-app-js-教程" aria-label="Permalink to &quot;💻 App JS 教程&quot;">​</a></h3><p>利用 jsBridge 扩展功能的完整指南。 <br><a href="/app-js-guide.html">查看教程 →</a></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:16px;background:var(--vp-c-bg-soft);"><h3 id="💾-备份与恢复" tabindex="-1">💾 备份与恢复 <a class="header-anchor" href="#💾-备份与恢复" aria-label="Permalink to &quot;💾 备份与恢复&quot;">​</a></h3><p>聊天记录等重要数据的备份方案。 <br><a href="/backup-restore.html">查看教程 →</a></p></div></div><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>此仓库详细记录了使用 <a href="https://mt2.cn/" target="_blank" rel="noreferrer">MT 管理器</a> 修改超星 <a href="https://app.chaoxing.com/" target="_blank" rel="noreferrer">学习通</a> 6.7.2 版本的具体流程。在此之前，全网中<strong>只</strong>找到<strong>可以拖动进度条</strong>的 4.3.4 版本和少量相关教程，可见相关资源匮乏。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><ul><li>有些操作需要 MT 会员，可使用 <a href="http://normalplayer.top/" target="_blank" rel="noreferrer">NP 管理器</a> 代替</li><li>阅读此教程需要一定的逆向知识</li><li>遇到问题可以使用 AI 辅助分析</li></ul></div><h2 id="ai-辅助修改" tabindex="-1">AI 辅助修改 <a class="header-anchor" href="#ai-辅助修改" aria-label="Permalink to &quot;AI 辅助修改&quot;">​</a></h2><p>由于 ProGuard 的混淆缘故，即使知道怎么修改，不同版本修改的位置也不一样。但借助 AI 可以快速定位问题，除了 <a href="/guide/unpack-repair.html">脱壳修复</a> 需要手动操作外，其他的分析都可以交给 AI 来做。</p><h3 id="推荐工具" tabindex="-1">推荐工具 <a class="header-anchor" href="#推荐工具" aria-label="Permalink to &quot;推荐工具&quot;">​</a></h3><ul><li><strong><a href="https://mt2.cn/guide/reverse/apk-mcp.html" target="_blank" rel="noreferrer">APK MCP</a></strong> — 手机端使用</li><li><strong><a href="https://github.com/zinja-coder/jadx-ai-mcp/releases" target="_blank" rel="noreferrer">jadx-ai-mcp</a></strong> — 电脑端使用</li></ul><h3 id="通用提示词" tabindex="-1">通用提示词 <a class="header-anchor" href="#通用提示词" aria-label="Permalink to &quot;通用提示词&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 1、先让ai了解项目</span></span>
<span class="line"><span>调用jadx/mt mcp服务，打开apk，了解apk信息</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 2、限定ai给出的修改意见，目前mcp提供的修改功能都不好用，推荐自行修改</span></span>
<span class="line"><span>你无需修改，只负责提供意见。修改意见：反编译代码并不好修改，常用的修改方案有</span></span>
<span class="line"><span>更改某处判断（只需更改某行代码）、清空某个方法（阻止方法执行）、</span></span>
<span class="line"><span>修改方法返回值（只需在末尾添加一行代码，且只限基本类型），</span></span>
<span class="line"><span>像在中间添加调用方法等，也可以使用但比较麻烦，</span></span>
<span class="line"><span>因为涉及到smali的寄存器，所以优先级并不高。</span></span></code></pre></div><h2 id="外部资源" tabindex="-1">外部资源 <a class="header-anchor" href="#外部资源" aria-label="Permalink to &quot;外部资源&quot;">​</a></h2><ul><li><a href="https://bbs.binmt.cc/thread-145359-1-1.html" target="_blank" rel="noreferrer">学习通修改教程终版</a> — 初版教程</li><li><a href="https://bbs.binmt.cc/thread-150946-1-1.html" target="_blank" rel="noreferrer">Web 调试逆向</a> — 网页调试教程</li><li><a href="https://bbs.binmt.cc/thread-160969-1-1.html" target="_blank" rel="noreferrer">adb 远程调试网页</a> — 调试方法</li><li><a href="https://bbs.binmt.cc/thread-157986-1-1.html" target="_blank" rel="noreferrer">学习通伪造位置签到</a> — 位置签到解析</li><li><a href="https://bbs.binmt.cc/thread-151654-1-1.html" target="_blank" rel="noreferrer">油猴插件代码</a> — 填空题粘贴</li></ul><h2 id="资料" tabindex="-1">资料 <a class="header-anchor" href="#资料" aria-label="Permalink to &quot;资料&quot;">​</a></h2><p><a href="https://www.123684.com/s/o1cqVv-a1hjH" target="_blank" rel="noreferrer">https://www.123684.com/s/o1cqVv-a1hjH</a></p><h2 id="友链" tabindex="-1">友链 <a class="header-anchor" href="#友链" aria-label="Permalink to &quot;友链&quot;">​</a></h2><p>学习通微信版（网页）：<a href="https://mooc1.chaoxing.com/course/phone/courselisthead" target="_blank" rel="noreferrer">https://mooc1.chaoxing.com/course/phone/courselisthead</a></p>`,19)])])}const u=e(d,[["render",l]]);export{b as __pageData,u as default};
